create table dirkspzm32.edi_vda4987_pack (
    document_id         varchar2(32 char) not null enable,
    ipig_id             varchar2(32 char) not null enable,
    pack_item_id        varchar2(32 char) not null enable,
    pos                 number(4, 0) not null enable,
    shipping_marks_desc varchar2(35 char),
    marking_type_code   varchar2(3 char),
    object_id1          varchar2(35 char),
    code_qualifier1     varchar2(3 char),
    object_id2          varchar2(35 char),
    code_qualifier2     varchar2(3 char),
    object_id3          varchar2(35 char),
    code_qualifier3     varchar2(3 char),
    object_id4          varchar2(35 char),
    code_qualifier4     varchar2(3 char),
    object_id5          varchar2(35 char),
    code_qualifier5     varchar2(3 char),
    batch_number        varchar2(35 char),
    expiration_date     date,
    manufacturing_date  date,
    jis_module_id       varchar2(35 char),
    lhm_number          varchar2(12 char),
    tray_number         varchar2(35 char),
    control_number      number(3, 0)
);

alter table dirkspzm32.edi_vda4987_pack
    add constraint pk_edi_vda4987_pack primary key ( pack_item_id )
        using index enable;


